INSERT INTO `categories` (`id`, `name`, `intro`, `slug`, `parent_id`, `is_active`, `sort_order`, `created_at`, `updated_at`) VALUES
(1000201, 'Bách khoa tri thức', 'Sách luôn là một phần không thể thiếu trong cuộc sống. Với sứ mệnh đồng hành cùng sự phát triển của trẻ em Việt, Đinh Tị Books thấu hiểu nhu cầu đọc, khả năng khám phá phát triển của mỗi độ tuổi khác nhau để cho ra đời những tựa sách phù hợp nhất.Việc chăm sóc, nuôi dạy một em bé luôn là việc quan trọng nhất của các bậc phụ huynh, thầy cô và nhà trường. Bên cạnh những bài học dạy trẻ phát triển kỹ năng sống thì những cuốn sách Bách khoa tri thức được ví như những người bạn đồng hành của trẻ trong suốt những năm tháng trưởng thành. Tại Đinh Tị Books, độc giả dễ dàng bắt gặp hình ảnh những em bé dưới 6 tuổi cũng có thể đọc sách Bách khoa tri thức với những kiến thức, thông tin rất mạch lạc, khoa học được biên soạn lồng ghép trong các tựa sách tương tác. Lớn hơn chút nữa, từ độ tuổi 6-15+ thì bố mẹ có rất nhiều lựa chọn cho các con, những cuốn sách Bách khoa tri thức đa dạng về chủ đề, chứa đựng nhiều kiến thức hấp dẫn, thu hút niềm đam mê đọc sách và phát triển tư duy sáng tạo của trẻ. Bách khoa tri thức là một tủ sách lớn, một “vựa tri thức” bao la với nội dung hấp dẫn, chủ đề kiến thức bao quát trên nhiều lĩnh vực khác nhau như: các hành tinh, vũ trụ, Trái Đất, thiên nhiên, khoa học, lịch sử, địa lý, động vật, thực vật, con người, v.v… Sách được minh họa bằng những bức tranh sinh động, ngôn ngữ dễ hiểu. Mỗi một chủ đề giúp trẻ tăng nhận thức, sự hiểu biết, nâng cao khả năng sáng tạo và tư duy khám phá. Trẻ được tiếp xúc sớm với sách đã là một lợi thế, trẻ say mê đọc sách Bách khoa tri thức là điều tuyệt vời mà cha mẹ nào cũng mong đợi. Đinh Tị Books kỳ vọng những cuốn sách bách khoa không chỉ giúp trẻ xây dựng nền tảng kiến thức vững chắc, mà còn khơi dậy, nuôi dưỡng trí tuệ cho trẻ ngay từ khi còn nhỏ. Tủ sách Bách khoa tri thức Đinh Tị Books nổi tiếng với các tựa sách: Bách khoa thư về khoa học, Bách khoa toàn thư về địa lý, Bách khoa thư về các loại phương tiện giao thông, Bách khoa thư về dòng thời gian của vạn vật, Khám phá đầu tiên của tớ, Những câu chuyện khoa học dành cho thiếu nhi, 100 bí ẩn đáng kinh ngạc, What a waste - Kiểm soát rác thải, bảo vệ môi trường, Atlas khổng lồ bằng tranh, v.v…Hãy cùng bước vào thế giới sách Bách khoa tri thức của Đinh Tị Books để sẵn sàng tinh thần tự lập, tự chủ cho những bước tiến mới ở tương lai.', 'bach-khoa-tri-thuc', 0, 1, 0, '2025-09-25 10:05:41', '2025-09-25 22:32:33'),
(1000202, 'Người kể chuyện', 'Cố Đệ nhất phu nhân nước Mỹ Jacqueline Kennedy từng nói: “Có nhiều cách nhỏ bé để mở rộng thế giới của con trẻ và tình yêu với sách là cách tốt nhất để làm điều này.” Với vai trò của một đơn vị xuất bản sách thiếu nhi, Đinh Tị thấu hiểu lợi ích của việc đọc sách, nhất là việc đọc sách sớm cho trẻ ngay từ khi trẻ còn trong bụng mẹ.Do đó, Đinh Tị Books đã hình thành và phát triển Tủ sách Người kể chuyện. Đây là tủ sách tập hợp những cuốn sách kể chuyện phong phú, từ những câu chuyện cổ tích Việt Nam cho đến những câu chuyện cổ nổi tiếng trên toàn thế giới, được hàng triệu bạn nhỏ yêu thích. Tủ sách Người kể chuyện của Đinh Tị Books tập hợp rất nhiều tựa sách hay như: Illustrated Classics, Truyện cổ tích Việt Nam, Truyện kể cho bé trước giờ đi ngủ - Ngày xửa ngày xưa, Truyện cổ tích lừng danh thế giới, 365 truyện kể trước giờ đi ngủ…Tủ sách Người kể chuyện luôn luôn được đội ngũ Đinh Tị sáng tạo, làm mới khi thì bằng những bộ tranh vẽ độc quyền như trong bộ truyện cổ tích Việt Nam, khi thì bằng ngôn ngữ hồn nhiên, giàu tình cảm với những bức vẽ minh hoạ trong trẻo, giàu màu sắc. Tủ sách Người kể chuyện không đơn thuần truyền tải những câu chuyện nuôi dưỡng ước mơ, đúc kết những bài học đạo đức sâu sắc cho trẻ mà thông qua tủ sách này, Đinh Tị Books mong muốn giữ gìn nét đẹp văn hóa đọc của người Việt Nam, tôn vinh tình yêu thương của những người bà, người mẹ, các thầy cô giáo đã và đang đồng hành nuôi dưỡng thế hệ măng non bằng những câu chuyện đầy cảm hứng để cùng trẻ xây dựng những năm tháng tuổi thơ thật ngọt ngào, nuôi dưỡng cảm xúc, lòng nhân văn, nhân hậu và cách sống cho trẻ.Tủ sách Người kể chuyện của Đinh Tị Books tự hào lan tỏa tình yêu đọc sách đến với rất nhiều các bậc phụ huynh và các bạn nhỏ trên khắp Việt Nam. Luôn truy cập Website của Đinh Tị Books để cập nhật những tựa sách mới xuất bản các bạn nhé!', 'nguoi-ke-chuyen', 0, 1, 0, '2025-09-25 10:05:41', '2025-09-25 22:33:06'),
(1000203, 'Sách kỹ năng', 'Những cuốn sách có nội dung truyền tải các kỹ năng sống hữu ích cho trẻ, giúp trẻ biết bình tĩnh đối mặt với những khó khăn có thể gặp phải trong cuộc sống.', 'sach-ky-nang', 0, 1, 0, '2025-09-25 10:05:41', '2025-09-25 22:33:25'),
(1000204, 'Sách tiếng Anh', 'Những cuốn sách tham khảo hữu ích, giúp trẻ cải thiện các kỹ năng tiếng Anh quan trọng là nghe-nói-đọc-viết.', 'sach-tieng-anh', 0, 1, 0, '2025-09-25 10:05:41', '2025-09-25 22:33:36'),
(1000205, 'Tương tác thông minh', 'Tiếp xúc với sách từ sớm mang lại cho trẻ nhiều lợi ích về tư duy và cảm xúc. Thế nhưng, để trẻ hào hứng đọc sách, đọc sách lâu hơn và nhận được nhiều giá trị nhất từ sách thì không phải dòng sách nào cũng tự nhiên làm được. Sách tương tác thông minh ra đời, với các thiết kế độc đáo như: tích hợp âm thanh, miếng lật mở, chuyển động…đã thành công thu hút sự chú ý, kích thích trí tò mò và yêu thích đọc sách hơn của trẻ 0-6 tuổi!\nSách tương tác thông minh là gì?\nSách tương tác thông minh (interactive books) đã xuất hiện từ lâu trên thế giới, và nhận được sự yêu thích của đông đảo phụ huynh thông thái, đặc biệt tại các nước phát triển như Anh, Mỹ, Đức. Bằng tình yêu và tâm huyết dành cho thiếu nhi, những năm qua Đinh Tị Books đầu tư, nghiên cứu và xuất bản thành công Tủ sách Tương tác chất lượng cao, thu hút sự quan tâm, yêu thích của đông đảo độc giả trên toàn quốc. Khác với các loại sách truyền thống, sách tương tác là dòng sách sáng tạo cao, kết hợp công nghệ xuất bản hiện đại nhằm mở rộng biên độ trải nghiệm, vượt qua giới hạn của việc đọc - kể - nghe thông thường mà tham gia tương tác đa chiều với nội dung trong sách, kích thích sự sáng tạo của trẻ và giúp trẻ phát triển toàn diện đa giác quan.\nNhững lợi ích của sách tương tác thông minh cho trẻ 0-6 tuổi', 'tuong-tac-thong-minh', 0, 1, 0, '2025-09-25 10:05:41', '2025-09-25 22:33:46'),
(1000206, 'Văn học Amun', 'Amunbooks là dòng sách văn học tình cảm lãng mạn được nhiều độc giả yêu mến từ lâu. Mang theo sứ mệnh đưa bạn đọc đến gần hơn với những tác giả, tác phẩm tiểu thuyết tình cảm lãng mạn trong nước và ngoài nước, nuôi dưỡng những tâm hồn trẻ cảm nhận thế giới tình yêu muôn hình vạn trạng, rực rỡ sắc màu.Trong những năm qua, Amunbooks đã đẩy mạnh việc phát hành các tác phẩm nổi tiếng, những câu chuyện tình yêu đẹp đẽ mà sâu sắc, được đông đảo độc giả đón nhận. Dòng sách của Amunbooks rất đa dạng về chủ đề, chủng loại để bạn đọc có thể thỏa sức tìm kiếm tác phẩm phù hợp và yêu thích. Nổi bật như: Đợi khi tôi có tội, Hãy nhắm mắt khi anh đến, Mãi mãi là bao xa, Bến xe, Eo thon nhỏ, All in love - Ngập tràn yêu thương, Tháng năm có anh, ký ức thành hoa, Gửi thanh xuân, v.v…Theo thời gian, tủ sách Văn học của Đinh Tị Books sẽ ngày càng đa dạng hơn, hấp dẫn hơn. Những tác phẩm văn học mang dấu ấn của thời gian, mang giá trị sống tốt đẹp sẽ được Đinh Tị Books tiếp tục khai thác và phát hành, góp phần nuôi dưỡng và làm xanh mát khu vườn tâm hồn của độc giả ở mọi lứa tuổi khác nhau.', 'van-hoc-amun', 0, 1, 0, '2025-09-25 10:05:41', '2025-09-25 22:34:05'),
(1000207, 'Văn học kinh điển', 'Văn học Kinh Điển là một trong những dòng sách có giá trị cao và bền vững nhất, nhưng cũng đòi hỏi sự nghiên cứu đầu tư công phu nhất. Hiểu được giá trị lâu dài của văn chương với đời sống xã hội, cũng như khả năng làm giàu đẹp thêm ngôn ngữ tiếng Việt, Đinh Tị Books đã dành nhiều thời gian và tâm huyết lựa chọn bản dịch, tổ chức bản thảo, minh họa cũng như làm mới nhiều tác phẩm đã từng được yêu thích bởi nhiều thế hệ của những văn hào như Charles Dickens, L. M. Montgomery, Louisa May Alcott, Sir Arthur Conan Doyle, Maurice Leblanc, Hector Malot... Đây là dòng sách mang lại những lợi ích tinh thần vô giá, làm gia tăng hiểu biết, nuôi dưỡng tâm hồn người đọc. Không chỉ vậy. văn học kinh điển là người bạn thủy chung, đồng hành với người đọc trong suốt chiều dài của cuộc đời, từ tuổi nhỏ cho đến khi trưởng thành.', 'van-hoc-kinh-dien', 0, 1, 0, '2025-09-25 10:05:41', '2025-09-25 22:34:34'),
(1000208, 'Văn học thiếu nhi', 'Thấu hiểu vai trò quan trọng của một nhà xuất bản sách thiếu nhi, khi xây dựng ý tưởng xuất bản những tựa sách văn học thiếu nhi, Đinh Tị Books luôn đặt yếu tố phù hợp lên hàng đầu. Đó là những tựa sách được khai thác bản quyền trong nước và quốc tế, thấm đẫm chất nhân văn và những bài học cuộc sống ý nghĩa. Những cuốn sách này được dịch mới, chuyển thể bằng các hình thức thơ, văn xuôi, giàu hình ảnh, giàu vần điệu và nhạc điệu, giúp người đọc nhỏ tuổi tiếp thu nhanh và dễ dàng ghi nhớ. Những nhân vật có trong các tác phẩm văn học thiếu nhi rất gần gũi và đáng yêu giúp trẻ phát hiện và cảm nhận được những vẻ đẹp của thiên nhiên, những điều thú vị của cuộc sống, hình thành nên những cảm xúc đẹp và nhân văn, nuôi dưỡng tâm hồn, tình yêu với văn học. Bởi thế mà văn học thiếu nhi của Đinh Tị Books luôn có sức hấp dẫn, lôi cuốn độc giả nhí.Những bộ sách văn học thiếu nhi nổi tiếng của Đinh Tị Books phải kể đến như: Truyện cổ Grimm, Nghìn lẻ một đêm, Không gia đình, Những tấm lòng cao cả, Công tử nhỏ Fauntleroy, Ông tớ là cây anh đào, Kẻ trộm sao, v.v…', 'van-hoc-thieu-nhi', 0, 1, 0, '2025-09-25 10:05:41', '2025-09-25 22:34:43'),
(1000209, 'Văn học trinh thám', 'Những câu chuyện phiêu lưu, mạo hiểm, ly kỳ từ lâu đã thu hút con người một cách tự nhiên. Dòng sách văn học trinh thám là một dòng sách giải trí đặc biệt, không chỉ bởi tính chất ly kỳ, hấp dẫn của các vụ án, các hoạt động điều tra tìm ra thủ phạm, mà còn miêu tả, thăm dò những góc khuất trong đời sống tâm lý xã hội.\nĐó là lý do mà dòng văn học đặc biệt này rất được yêu thích bởi nhiều nhà văn hóa lớn trên thế giới như Umberto Eco, Gabriel Garcia Marquez... Sách văn học trinh thám của Đinh Tị Books cũng mang lại những ấn tượng khó phai trong lòng độc giả với những tác phẩm luôn được cập nhật mới, chọn lọc và tổ chức bản thảo vô cùng kĩ lưỡng.\nTrong đó phải kể đến nhiều tác phẩm nổi bật của những nhà văn trinh thám hàng đầu thế giới như: Conan Doyle, Maurice Leblanc, Higashino Keigo, Robert Dugoni, Rachel Caine, Melinda Leigh, v.v…', 'van-hoc-trinh-tham', 0, 1, 0, '2025-09-25 10:05:41', '2025-09-25 22:34:52');
