INSERT INTO `products` (`id`, `name`, `slug`, `short_desc`, `image_url`, `price`, `isbn13`, `sku`, `authors`, `translators`, `illustrators`, `publisher_name`, `publish_year`, `pages`, `dimensions_raw`, `width_cm`, `height_cm`, `thickness_mm`, `age_min`, `age_max`, `sale_price`, `sale_start`, `sale_end`, `sale_active`, `is_active`, `created_at`, `updated_at`, `view_count`) VALUES
(2000081, '24 giờ dưới đại dương', '24-gio-duoi-dai-duong', 'Trải nghiệm cảm giác lặn xuống lòng đại dương bên trong một tàu lặn.  Quan sát “tuyết biển” và khám phá lý do vì sao nó lại quan trọng. Cùng các nhà khoa học khám phá xác cá voi dưới đáy biển sâu. Quan sát các miệng phun thủy nhiệt - nơi có rất nhiều sinh vật kỳ lạ sinh sống. Chiêm ngưỡng ánh sáng phát ra từ các sinh vật phát quang trong vùng tối nhất của đại dương.', 'https://dinhtibooks.com.vn/images/products/2025/07/large/z6835623245758_ff1768f1ed8dd6503c326abff29d78fc_1753325951.webp', 95200.00, '', '', 'Lời: Lan Cook; Minh họa: Laurent Kling', 'Minh Trang', '', 'Nhà xuất bản Tri Thức', '2025', 72, '18,8 x 25', 18.80, 25.00, 0.00, 6, 15, 76160.00, '2025-09-24 11:38:14', '2025-10-02 11:38:14', 0, 1, '2025-09-25 10:05:41', '2026-03-09 17:25:31', 2),
(2000082, '24 giờ trong sở thú', '24-gio-trong-so-thu', 'Bạn đã bao giờ thắc mắc chuyện gì xảy ra ở sở thú ngoài việc các nhân viên cho động vật ăn và vệ sinh chuồng trại của chúng chưa? Hãy sẵn sàng bước vào hành trình 24 giờ đầy bất ngờ tại một trong những sở thú nhộn nhịp nhất thế giới nhé! Không chỉ là nơi nuôi dưỡng, đó còn là trung tâm bảo tồn sinh học với những nhiệm vụ khó tin... nhưng có thật. Bạn sẽ được tìm hiểu điều gì xảy ra trong sở thú từ lúc bình minh cho đến khi màn đêm buông xuống. Người ta kiểm tra sức khỏe cho một con trăn khổng lồ ra sao, cách sở thú chuẩn bị cho sự kiện giới thiệu một động vật mới đến thế nào, điều gì sẽ xảy ra nếu một con vật bị mất tích? Và nhất là: Làm thế nào để xử lý hàng tấn chất thải động vật mỗi ngày? Quả thật, công việc tại sở thú chẳng hề đơn giản như bạn nghĩ đâu! Qua từng giờ đồng hồ, bạn đọc sẽ được tìm hiểu vô vàn những bí mật nơi \"hậu trường\" của sở thú đấy. Nhanh lên nào, chúng mình cùng khám phá ngay thôi! Sách khoa học theo định dạng truyện tranh, đưa các bạn nhỏ theo chân những nhân viên sở thú khám phá hàng trăm loài động vật trong sở thú Minh họa màu siêu đẹp, đáng yêu Mỗi loài động vật đều có câu chuyện riêng của mình Sách thích hợp cho bạn nhỏ từ 6 đến 15 tuổi.', 'https://dinhtibooks.com.vn/images/products/2025/05/large/bia-2d_24-gio-trong-so-thu---2025_1748417218.webp', 95200.00, '', '', 'Lời: Lan Cook; Minh họa: Stacey Thomas', 'Thùy Dương', '', 'Nhà xuất bản Tri Thức', '2025', 64, '18,8 x 25', 18.80, 25.00, 0.00, 6, 15, 76160.00, '2025-09-24 11:38:14', '2025-10-02 11:38:14', 0, 1, '2025-09-25 10:05:41', '2026-02-24 08:20:29', 0),
(2000083, 'Bí mật đôi mắt - Combo 4 tập', 'bi-mat-doi-mat-combo-4-tap', 'Chúng ta đều đã quá quen thuộc với đôi mắt của mình nhưng chưa chắc đã hiểu biết tường tận về nó. Vậy hãy để bộ sách Bí mật đôi mắt giúp bạn khám phá một cách kĩ lưỡng về “cửa sổ tâm hồn” nhé. Với nội dung đa dạng, toàn diện và cách dẫn dắt vấn đề vô cùng hấp dẫn, sáng tạo, bộ sách sẽ giúp chúng ta hiểu hơn về: - Cấu tạo của đôi mắt; - Các bệnh về mắt mà chúng ta dễ mắc phải cùng với cách phòng tránh; - Các thiết bị khám mắt và các loại kính mắt; - Các hành động bảo vệ đôi mắt. Còn chần chừ gì nữa, chúng ta hãy cùng mở sách ra để tìm hiểu về những bí mật của đôi mắt thôi nào', 'https://dinhtibooks.com.vn/images/products/2025/07/large/thiet-ke-chua-co-ten-5_1752811005.webp', 144000.00, '', '', 'Lời: Dongdongya; Hiệu đính: Cui Shanshan', 'Hà Giang', '', 'Nhà xuất bản Hồng Đức', '2025', 45, '20.5 x 25.4', 20.50, 25.40, 0.00, 6, 12, 115200.00, '2025-09-24 11:38:14', '2025-10-02 11:38:14', 0, 1, '2025-09-25 10:05:41', '2026-02-24 08:20:29', 0),
(2000084, 'Bí mật đôi mắt - Các bệnh về mắt', 'bi-mat-doi-mat-cac-benh-ve-mat', 'Chúng ta đều đã quá quen thuộc với đôi mắt của mình nhưng chưa chắc đã hiểu biết tường tận về nó. Vậy hãy để bộ sách Bí mật đôi mắt giúp bạn khám phá một cách kĩ lưỡng về “cửa sổ tâm hồn” nhé. Với nội dung đa dạng, toàn diện và cách dẫn dắt vấn đề vô cùng hấp dẫn, sáng tạo, bộ sách sẽ giúp chúng ta hiểu hơn về: - Cấu tạo của đôi mắt; - Các bệnh về mắt mà chúng ta dễ mắc phải cùng với cách phòng tránh; - Các thiết bị khám mắt và các loại kính mắt; - Các hành động bảo vệ đôi mắt. Còn chần chừ gì nữa, chúng ta hãy cùng mở sách ra để tìm hiểu về những bí mật của đôi mắt thôi nào', 'https://dinhtibooks.com.vn/images/products/2025/07/large/z6816307416560_45640e30fd5e393a630afa40efc68504_1752809518.webp', 36000.00, '', '', 'Lời: Dongdongya; Hiệu đính: Cui Shanshan', 'Hà Giang', '', 'Nhà xuất bản Hồng Đức', '2025', 45, '20.5 x 25.4', 20.50, 25.40, 0.00, 6, 12, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:01', 0),
(2000085, 'Bí mật đôi mắt - Các loại mắt kính', 'bi-mat-doi-mat-cac-loai-mat-kinh', 'Chúng ta đều đã quá quen thuộc với đôi mắt của mình nhưng chưa chắc đã hiểu biết tường tận về nó. Vậy hãy để bộ sách Bí mật đôi mắt giúp bạn khám phá một cách kĩ lưỡng về “cửa sổ tâm hồn” nhé. Với nội dung đa dạng, toàn diện và cách dẫn dắt vấn đề vô cùng hấp dẫn, sáng tạo, bộ sách sẽ giúp chúng ta hiểu hơn về: - Cấu tạo của đôi mắt; - Các bệnh về mắt mà chúng ta dễ mắc phải cùng với cách phòng tránh; - Các thiết bị khám mắt và các loại kính mắt; - Các hành động bảo vệ đôi mắt. Còn chần chừ gì nữa, chúng ta hãy cùng mở sách ra để tìm hiểu về những bí mật của đôi mắt thôi nào', 'https://dinhtibooks.com.vn/images/products/2025/07/large/z6816308466016_bbfe97369ee3fab92f1138fbe44316be_1752809480.webp', 36000.00, '', '', 'Lời: Dongdongya; Hiệu đính: Cui Shanshan', 'Hà Giang', '', 'Nhà xuất bản Hồng Đức', '2025', 45, '20.5 x 25.4', 20.50, 25.40, 0.00, 6, 12, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:01', 0),
(2000086, 'Bí mật đôi mắt - Hành động bảo vệ đôi mắt', 'bi-mat-doi-mat-hanh-dong-bao-ve-doi-mat', 'Chúng ta đều đã quá quen thuộc với đôi mắt của mình nhưng chưa chắc đã hiểu biết tường tận về nó. Vậy hãy để bộ sách Bí mật đôi mắt giúp bạn khám phá một cách kĩ lưỡng về “cửa sổ tâm hồn” nhé. Với nội dung đa dạng, toàn diện và cách dẫn dắt vấn đề vô cùng hấp dẫn, sáng tạo, bộ sách sẽ giúp chúng ta hiểu hơn về: - Cấu tạo của đôi mắt; - Các bệnh về mắt mà chúng ta dễ mắc phải cùng với cách phòng tránh; - Các thiết bị khám mắt và các loại kính mắt; - Các hành động bảo vệ đôi mắt. Còn chần chừ gì nữa, chúng ta hãy cùng mở sách ra để tìm hiểu về những bí mật của đôi mắt thôi nào', 'https://dinhtibooks.com.vn/images/products/2025/07/large/z6816310381351_93a5f2c7de57610b6f560aa36335f3d1_1752809440.webp', 36000.00, '', '', 'Lời: Dongdongya; Hiệu đính: Cui Shanshan', 'Hà Giang', '', 'Nhà xuất bản Hồng Đức', '2025', 45, '20.5 x 25.4', 20.50, 25.40, 0.00, 6, 12, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:01', 0),
(2000087, 'Bí mật đôi mắt - Thám hiểm hành tinh Mắt', 'bi-mat-doi-mat-tham-hiem-hanh-tinh-mat', 'Chúng ta đều đã quá quen thuộc với đôi mắt của mình nhưng chưa chắc đã hiểu biết tường tận về nó. Vậy hãy để bộ sách Bí mật đôi mắt giúp bạn khám phá một cách kĩ lưỡng về “cửa sổ tâm hồn” nhé. Với nội dung đa dạng, toàn diện và cách dẫn dắt vấn đề vô cùng hấp dẫn, sáng tạo, bộ sách sẽ giúp chúng ta hiểu hơn về: - Cấu tạo của đôi mắt; - Các bệnh về mắt mà chúng ta dễ mắc phải cùng với cách phòng tránh; - Các thiết bị khám mắt và các loại kính mắt; - Các hành động bảo vệ đôi mắt. Còn chần chừ gì nữa, chúng ta hãy cùng mở sách ra để tìm hiểu về những bí mật của đôi mắt thôi nào', 'https://dinhtibooks.com.vn/images/products/2025/07/large/z6816310421951_cdfd89900f0573cb8fbc9ee302d7942f_1752809401.webp', 36000.00, '', '', 'Lời: Dongdongya; Hiệu đính: Cui Shanshan', 'Hà Giang', '', 'Nhà xuất bản Hồng Đức', '2025', 45, '20.5 x 25.4', 20.50, 25.40, 0.00, 6, 12, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:01', 0),
(2000088, 'Cẩm nang sinh tồn (Hơn 100 kỹ năng sống còn cho các cuộc phiêu lưu nơi hoang dã)', 'cam-nang-sinh-ton-hon-100-ky-nang-song-con-cho-cac-cuoc-phieu-luu-noi-hoang-da', 'CẨM NANG SINH TỒN - Dòng sách thuộc lĩnh vực về sinh tồn, giúp người đọc biết được các kiến thức kỹ năng an toàn tự bảo vệ bản thân, chuẩn bị trước và trong cho mọi hoạt động dã ngoại, du lịch, trekking, marathon…. nơi hang dã. Sách được viết bởi Colin Towell là một huấn luyện viên sinh tồn của Hải Quân Hoàng gia, Huấn luyện viên trưởng của trường (SERE) Survival, Evasion, Resistance, and Escape. Sách mang tới 7 nội dung cấp thiết cho kỹ năng sinh tồn: - Cần chuẩn bị gì trước khi đi - Trên đường đi - Kiến thức về cắm trại - Cách tạo ra nơi trú ẩn - Nước và thức ăn - Các tình huống khẩn cấp - Sơ cứu Sách mang đến hơn 100 kỹ năng sống còn cho mọi cuộc phiêu lưu nơi hoang dã. - Chuẩn bị cho chuyến đi cả về tâm lý và các vật dụng, cách đi chơi theo nhóm với mọi độ tuổi - Các đồ dùng cần chuẩn bị cho 1 chuyến đi khám phá: đèn pin, balo, trang phục, sử dụng lều, - Nguy cơ giảm thân nhiệt, cách an toàn ở những vùng khí hậu khác nhau: Hoang mạc, trong rừng, đầm lầy, vùng biển. - Kỹ năng cắm trại, cách nhóm lửa, la bàn chỉ đường, các nút thắt, Cách chẻ củi - Cách xẻ thịt, làm chín thức ăn, tìm kiếm thức ăn trong rừng, tự làm phi tiêu, tránh côn trùng và động vật nguy hiểm. - Cách kêu cứu trợ, đối phó với động vật hoang dã, rơi xuống biển tạo phao - Kỹ năng sơ cứu: Gãy tay gãy chân, chảy máu, bong gân, hóc nghẹn, bất tỉnh, hồi sức tim phổi, hạ thân nhiệt, vết rắn cắn, ngộ độc, Tất cả các thông tin kỹ năng chia sẻ đều đã được kiểm chứng thực hành bởi các chuyên gia trong lĩnh vực sinh tồn, phòng vệ quân sự… Minh họa trực quan sinh động cho từng kỹ năng, giúp người đọc dễ theo dõi, hình dung và có thể ghi nhớ để thực hành được trong nhiều tình huống. Set quà tặng đi kèm với sách gồm: Bookmark bồi cứng Mẫu phiếu hành động khẩn cấp Thép đa năng kèm hướng dẫn sử dụng trên phong bì. Có thể đeo làm móc khóa.', 'https://dinhtibooks.com.vn/images/products/2025/04/large/bia-2d_cam-nang-sinh-ton_1743576411.webp', 294400.00, '', '', 'DK, Colin Towell', 'Thùy Dương', '', 'NXB Hà Nội', '2025', 328, '16 x 24', 16.00, 24.00, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:01', 0),
(2000089, 'Em yêu cơ thể - Lông mi', 'em-yeu-co-the-long-mi', 'Cơ thể tuyệt vời của chúng ta có rất nhiều bộ phận tuyệt vời', 'https://dinhtibooks.com.vn/images/products/2025/04/large/z6517483451140_0761f364fe4822f57b034c803b800f32_1744960179.webp', 24000.00, '', '', 'Robin Twiddy', 'Quỳnh Hương', '', 'NXB Văn Học', '2025', 27, '20.5 x 20.5', 20.50, 20.50, 0.00, 3, 9, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 11:02:23', 0),
