(2000095, 'Hiểu về nghề nghiệp - Các nhà khoa học làm gì?', 'hieu-ve-nghe-nghiep-cac-nha-khoa-hoc-lam-gi', 'Các nhà khoa học nghiên cứu cách thế giới vận hành. Nhiệm vụ của họ là đặt câu hỏi và tìm câu trả lời - bằng cách quan sát hoạt động của mọi thứ,thu thập bằng chứng và thực hiện cá cthí nghiệm. Có rất nhiều tên gọi khác nhau dành cho các ngành nghề khoa học khác nhau mà bạn sẽ được khám phá trong cuốn sách này.', 'https://dinhtibooks.com.vn/images/products/2025/05/large/z6654457020933_22e686c160350930cd0246e5a1038741_1748590401.webp', 120000.00, '', '', 'Lời: Tom Mumbray; Minh họa: Can Tuğrul & Geraldine Sy', 'Phạm Trang', '', 'NXB Hà Nội', '2025', 88, '21,6 x 27,6', 21.60, 27.60, 0.00, 9, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:01', 0),
(2000096, 'Hiểu về nghề nghiệp - Các phi hành gia làm gì?', 'hieu-ve-nghe-nghiep-cac-phi-hanh-gia-lam-gi', 'Bạn đã bao giờ mơ ước được bay vào không gian để khám phá vũ trụ chưa? Bạn có thể thực hiện ước mơ đó nếu trở thành một phi hành gia. Còn nếu bạn say mê không gian nhưng thích ở lại Trái Đất hơn thì sao? Việc đưa các phi hành gia và thiết bị vào không gian là một thử thách đòi hỏi phải có một đội ngũ LỚN cùng làm việc với nhau. Vì vậy, có thể có một công việc khác liên quan đến không gian phù hợp với bạn đấy.', 'https://dinhtibooks.com.vn/images/products/2025/05/large/z6654457021116_497d6f836944c0d52fbff9c493af91fa_1748590724.webp', 120000.00, '', '', 'Lời: Rob Lloyd Jones & Victoria M. Williams; Minh họa: Adam Allsuch-Boardman & Geraldine Sy', 'Phạm Trang', '', 'NXB Hà Nội', '2025', 88, '21,6 x 27,6', 21.60, 27.60, 0.00, 9, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:01', 0),
(2000097, 'Thiên văn học trực quan', 'thien-van-hoc-truc-quan', 'Thiên văn học là một chủ đề kỳ bí nhất, tò mò và còn nhiều điều thắc mắc chưa được giải đáp mà con người không ngừng nghiên cứu mỗi ngày. THIÊN VĂN HỌC TRỰC QUAN là cuốn sách nổi tiếng trong giới Thiên văn đến từ Nhà xuất bản DK uy tín, sách gốc: Astronomy: A visual guide của tác giả Ian Ridpath. Giới thiệu về nội dung sách: Chia thành tám phần đề cập đến mọi khía cạnh của thiên văn học. Tìm hiểu về lịch sử của những khám phá trong lĩnh vực này và các hiện tượng thiên văn, từ những nền văn minh đầu tiên của loài người cho đến ngày nay, sau đó thực hiện một chuyến tham quan trực quan hoành tráng về Hệ Mặt trời, thêm vào đó là những bức ảnh ngoạn mục nhất về các hành tinh. Bản hướng dẫn tuyệt vời giúp quan sát bầu trời đêm hàng tháng, với thông tin về 88 chòm sao, hơn 100 biểu đồ sao bao phủ cả hai bán cầu Bắc và Nam, và niên giám các sự kiện thiên văn trong thập kỷ tới. Cuốn sách sẽ giúp ích cho những độc giả thích quan sát bầu trời đêm và định vị các ngôi sao, thiên hà và các vật thể khác. Cuốn sách này sẽ cung cấp những nội dung tuyệt vời về thiên văn: Nguồn gốc của vũ trụ Lịch sử ngành thiên văn học Trọn vẹn hệ Mặt trời và các hành tinh Hướng dẫn quan sát bầu trời đêm Chi tiết 88 chòm sao, biểu đồ sao Lịch quan sát thiên văn hàng tháng, niêm giám cho đến năm 2031 về các hiện tượng đặc biệt Cuốn sách cũng đưa ra chỉ dẫn về cách quan sát bầu trời bằng mắt thường, ống nhòm và kính thiên văn. Đây là sách hướng dẫn hoàn hảo cho các nhà thiên văn nghiệp dư, cũng như một cuốn sách tham khảo tuyệt vời cho cả gia đình. Thông tin về Tác giả: http://www.ianridpath.com/cv/cv.html Sách được viết bởi tác Ian Ridpath, nhà văn, biên tập viên và là nhà thiên văn học, người đã dành cả cuộc đời cho đam mê nghiên cứu thiên văn học, ông sở hữu hơn 40 đầu sách làm tác giả hoặc biên tập viên. Cuốn sách được xuất bản bởi NXB DK uy tín nổi tiếng toàn cầu, tư liệu tham khảo chi tiết đáng giá đến từng con số.', 'https://dinhtibooks.com.vn/images/products/2025/06/large/z6740584211172_6ca8f37d73f2847372b77b758480d665_1750835364.webp', 400000.00, '', '', 'DK, Ian Ridpath', 'Ngọc Anh', '', 'NXB Thế Giới', '2025', 360, '19,5 x 23,3', 19.50, 23.30, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:01', 0),
(2000098, 'Tớ đeo kính!', 'to-deo-kinh', 'Xin chào, tên tớ là Joe và tớ đeo kính đấy. Một ngày nọ, tớ để ý thấy mình không thể nhìn rõ nhà cửa, cây cối hay bạn bè mình ở bên kia đường nữa. Tớ cảm thấy như thể đang nhìn xuyên qua một ô cửa sổ mờ sương vậy - nhưng lại chẳng có cái cửa sổ nào ở đó hết! Tớ không thể đếm được số chim đang đậu trên cành cây hay đọc được số hiệu những chiếc xe buýt đi ngang qua trước mặt mình', 'https://dinhtibooks.com.vn/images/products/2025/06/large/z6740631592631_fa19c54b8ad3f5aebf14b82867f17738_1750836133.webp', 36000.00, '', '', 'Lời: Helena Haraštová; Minh họa: Ana Kobern', 'Trannie', '', 'Nhà xuất bản Tri Thức', '2025', 32, '20,5 x 24,4', 20.50, 24.40, 0.00, 6, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:01', 0),
(2000099, 'Vật lý thật dễ hiểu - Chuyển động', 'vat-ly-that-de-hieu-chuyen-dong', 'Vật lý thật dễ hiểu là bộ sách đặc biệt dành cho lứa tuổi học sinh, giúp các em khám phá các kiến thức thú vị qua các trang sách được minh họa một cách sinh động. Bộ sách không chỉ giới thiệu các khái niệm, nguyên lý, hiện tượng mà còn hơn thế nữa: - Đề cập các kiến thức vật lý cơ bản, thiết thực, gần gũi với đời sống thực tế - Sử dụng minh họa trực quan - Kích thích niềm đam mê khoa học', 'https://dinhtibooks.com.vn/images/products/2025/05/large/z6569575957543_6e9c18fe6cb17790b8342c5a75dcad34_1746418172.webp', 44000.00, '', '', 'Nhạc Tân Vũ; Trương Vĩ', 'Nguyễn Đức Vịnh', '', 'Nhà xuất bản Hồng Đức', '2025', 48, '17 x 24', 17.00, 24.00, 0.00, 6, 15, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:01', 0),
