(2000206, '(BẢN ĐẶC BIỆT) COMBO: CÁ VOI CÔ ĐƠN (3 TẬP) - HÀM YÊN', 'ban-dac-biet-combo-ca-voi-co-don-3-tap-ham-yen', 'Cô luôn nghĩ mình đích thực là Eleven Girl. Eleven Girl muốn tìm được Mr Funny của đời mình. Thế rồi vào buổi tối hôm ấy, cô trằn trọc mãi vẫn không sao ngủ nổi. Cô biết là sự tình đã mất kiểm soát. Trái tim cô trải nghiệm một sự rung động mà trước đây chưa từng có. Có một người đã lẳng lặng đi vào trong trái tim cô. Anh yên tĩnh, chu đáo, dịu dàng, bao dung..., lại còn rất thẹn thùng, rất đáng yêu nữa. Không phải kiểu người hài hước thú vị, khéo ăn khéo nói như cô từng ao ước, nhưng lại thường xuyên có thể chọc cho cô cười. Anh rất cao, khí chất lại thanh tao trong sáng, dung mạo thì không chê được ở điểm nào! Lại còn là một nghệ nhân nữa! Một nghệ nhân cực đỉnh! Nhưng, như vậy vẫn không được! Chiêm Hỷ kéo chăn trùm đầu, hai chân đều run lên lẩy bẩy, trong lòng thầm nghĩ, phải làm sao, phải làm sao, phải làm sao, phải làm sao đây? Lạc Tĩnh Ngữ là một người câm điếc. Nếu để mẹ cô biết được việc này, có khi anh sẽ bị làm thành một chú cá khô tê cay mất!', 'https://dinhtibooks.com.vn/images/products/2024/01/31/large/anh-san-pham-17-03_1706669930.webp', 595200.00, '', '', 'Hàm Yên', 'Nguyễn Đức Vịnh', '', 'NXB Văn Học', '2024', 0, '14,5 x 20,5', 14.50, 20.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000207, 'COMBO: CÁ VOI CÔ ĐƠN (3 TẬP) - HÀM YÊN', 'combo-ca-voi-co-don-3-tap-ham-yen', 'Cô luôn nghĩ mình đích thực là Eleven Girl. Eleven Girl muốn tìm được Mr Funny của đời mình. Thế rồi vào buổi tối hôm ấy, cô trằn trọc mãi vẫn không sao ngủ nổi. Cô biết là sự tình đã mất kiểm soát. Trái tim cô trải nghiệm một sự rung động mà trước đây chưa từng có. Có một người đã lẳng lặng đi vào trong trái tim cô. Anh yên tĩnh, chu đáo, dịu dàng, bao dung..., lại còn rất thẹn thùng, rất đáng yêu nữa. Không phải kiểu người hài hước thú vị, khéo ăn khéo nói như cô từng ao ước, nhưng lại thường xuyên có thể chọc cho cô cười. Anh rất cao, khí chất lại thanh tao trong sáng, dung mạo thì không chê được ở điểm nào! Lại còn là một nghệ nhân nữa! Một nghệ nhân cực đỉnh! Nhưng, như vậy vẫn không được! Chiêm Hỷ kéo chăn trùm đầu, hai chân đều run lên lẩy bẩy, trong lòng thầm nghĩ, phải làm sao, phải làm sao, phải làm sao, phải làm sao đây? Lạc Tĩnh Ngữ là một người câm điếc. Nếu để mẹ cô biết được việc này, có khi anh sẽ bị làm thành một chú cá khô tê cay mất!', 'https://dinhtibooks.com.vn/images/products/2024/01/30/large/combo_1706598835.webp', 595200.00, '', '', 'Hàm Yên', 'Nguyễn Đức Vịnh', '', 'NXB Văn Học', '2024', 0, '14,5 x 20,5', 14.50, 20.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000208, 'Combo (2 tập): Đèn sao hoang dã', 'combo-2-tap-den-sao-hoang-da', '“Combo (2 tập): Đèn sao hoang dã” là ấn phẩm thuộc danh mục Văn học Amun. Tác giả: Chung Cận. Dịch giả: Thanh Thiên. Phù hợp: nan. Kích thước: 14 x 20,5 ; Số trang: 440 trang ; NXB: NXB Văn Học ; Năm XB: 2025. Mô tả đang được cập nhật chi tiết.', 'https://dinhtibooks.com.vn/images/products/2025/05/large/den-sao-hoang-da_1747365248.webp', 342400.00, '', '', 'Chung Cận', 'Thanh Thiên', '', 'NXB Văn Học', '2025', 440, '14 x 20,5', 14.00, 20.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000209, 'Combo (2T): Vợ ngọt', 'combo-2t-vo-ngot', 'Giản Tích là bác sĩ khoa sản xinh đẹp, nhu thuận. Ôm ấp mối tình đơn phương với một kẻ không ra gì cho đến ngày gặp được Hạ Nhiên. Nếu không có anh, cô đã không dũng cảm như vậy, dũng cảm nhìn lại bản thân, dũng cảm buông bỏ thứ tình cảm chưa từng được coi trọng. Lúc gặp Giản Tích, Hạ Nhiên là một tên lưu manh chính hiệu, làm công việc đòi nợ thuê, ăn nói thô lỗ, hành động ngang tàng. Nếu không có cô, anh đã không dũng cảm như vậy, dũng cảm theo đuổi một người vốn không hề thích hợp, dũng cảm rũ bỏ quá khứ, thử làm lại cuộc đời.', 'https://dinhtibooks.com.vn/images/products/2025/03/large/anh-bia-vo-ngot_1742780691.webp', 326400.00, '', '', 'Giảo Xuân Bính', 'Nguyễn Đức Vịnh', '', 'NXB Văn Học', '2025', 0, '', 0.00, 0.00, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000210, 'Combo 2 tập: Tuyệt đối cưng chiều - Bản đặc biệt', 'combo-2-tap-tuyet-doi-cung-chieu-ban-dac-biet', 'Sau sự kiện sinh nhật của Kiều Lạc Chỉ, tình cảm Ngu Trĩ Nhất dành cho Thời Dịch bước vào giai đoạn mới. Cô nghĩ... liệu có phải Thời Dịch cũng thích cô, dù chỉ là một chút, kiểu con trai thích con gái ấy? Nhưng Thời Dịch chưa bao giờ nói những điều đó, còn cô lại nhút nhát không dám hỏi.', 'https://dinhtibooks.com.vn/images/products/2025/07/large/tuyet-doi-cung-chieu-04_1752027077.webp', 358400.00, '', '', 'Giang La La', 'Lưu Vân', '', 'NXB Văn Học', '2025', 0, '14.5 x 20.5', 14.50, 20.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0);
INSERT INTO `products` (`id`, `name`, `slug`, `short_desc`, `image_url`, `price`, `isbn13`, `sku`, `authors`, `translators`, `illustrators`, `publisher_name`, `publish_year`, `pages`, `dimensions_raw`, `width_cm`, `height_cm`, `thickness_mm`, `age_min`, `age_max`, `sale_price`, `sale_start`, `sale_end`, `sale_active`, `is_active`, `created_at`, `updated_at`, `view_count`) VALUES
(2000211, 'Combo đặc biệt : Câu chuyện không ai biết ấy 2T', 'combo-dac-biet-cau-chuyen-khong-ai-biet-ay-2t', 'Cô luôn sống trong thế giới của riêng mình, thỉnh thoảng mới tiếp nhận một số người mà cô cho là “chấp nhận” được. Còn bây giờ, có người đang dùng cách khác của họ, cạy toang cánh cửa thế giới của cô ra, nơi mà họ cho rằng sẽ tồn tại những điều kỳ quái hoặc bí mật nào đó. Thế rồi họ ào ạt xông vào, vươn tay xé toạc thế giới nội tâm của cô, mở mắt thật to để nhìn, rồi gầm rú, gào thét, cười khả ố để tìm những thứ mà họ nghĩ là bẩn thỉu, không thể cho người khác xem ấy. Cô thực sự muốn hỏi bọn họ, bọn họ đã tìm thấy chưa? Rất nhiều người nhìn cô, như đang đợi thời khắc cô suy sụp, cô chửi rủa. Nhưng sau cùng, cô chỉ mỉm cười. Trần Minh Sinh chưa bao giờ nhìn thấy cô cười như thế, thậm chí chưa bao giờ thấy dáng vẻ nhẹ nhõm ấy ở nơi cô, trông cô như đã tìm được đáp án mà mình tìm kiếm bấy lâu vậy. Cô nhìn xung quanh, đèn đường, trần nhà, bàn nhựa và cả những người đang nhìn cô chòng chọc ấy… cuối cùng, nhìn vào mắt Trần Minh Sinh. Ánh mắt cô có vài phần dịu dàng, vài phần phóng khoáng, thậm chí có vài phần kiêu ngạo. Cô nói với anh bằng giọng nhẹ bẫng: “Trần Minh Sinh, khát khao của em là thật, tình cảm của em cũng là thật, em rất thẳng thắn, cũng rất chân thành.”', 'https://dinhtibooks.com.vn/images/products/2024/07/18/large/z5644142836284_e1ee590183dd5009920e10b8909bffa4_1721271252.webp', 326400.00, '', '', 'Twentine', 'Bình Nguyên', '', 'NXB Thanh Niên', '2024', 0, '14 x 20,5', 14.00, 20.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000212, 'Combo đặc biệt : Trở về năm tháng bố tôi là hot boy 2T', 'combo-dac-biet-tro-ve-nam-thang-bo-toi-la-hot-boy-2t', 'Cô gái lặng lẽ ngồi cạnh anh, anh dịu dàng nhìn cô. Cô vẫn như vậy, chẳng hề thay đổi, vẫn là Lục Yên trong trí nhớ của anh, còn anh đã không còn là thiếu niên năm nào nữa. Nhưng dù đôi mắt anh đã nhìn thấy bao nhiêu thăng trầm của cuộc đời, dù trái tim anh đã lạnh lẽo, cô độc như thế nào, thì lúc này đây, nhìn thấy cô… trong lòng anh lại chất chứa sự dịu dàng. Anh và cô ngồi bên hồ ngắm hoàng hôn dần phai nhạt. “Tiểu Yên đã từng thích ai chưa?” “Chưa ạ, bố con không cho yêu sớm.” “Còn tôi thì có rồi.” Lục Yên nhìn anh bằng ánh mắt hiếu kỳ. Nụ cười của anh chan chứa niềm hạnh phúc vô tận xen lẫn nỗi chua chát đắng cay. “Thích cô ấy là hạnh phúc cả đời của tôi.”', 'https://dinhtibooks.com.vn/images/products/2024/07/18/large/z5644142851625_3fa5e10a0cace54630cab2e58194a2c1_1721270511.webp', 460800.00, '', '', 'Xuân Phong Lựu Hỏa', 'Vải Thiều', '', 'NXB Văn Học', '2024', 0, '14.5 x 20.5', 14.50, 20.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
