roducts/2023/12/01/large/hon-dao-bi-mat_combo-2t_1701379615.webp', 238400.00, '', '', 'Jules Verne', 'Phùng Nga', '', 'NXB Thanh Niên', '2023', 0, '14,5 x 20,5', 14.50, 20.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000236, 'Illustrated Classics - Những cuộc phiêu lưu kỳ thú - Robin Hood, Gulliver du ký, Moonfleet', 'illustrated-classics-nhung-cuoc-phieu-luu-ky-thu-robin-hood-gulliver-du-ky-moonfleet', '“Illustrated Classics - Những cuộc phiêu lưu kỳ thú - Robin Hood, Gulliver du ký, Moonfleet” là ấn phẩm thuộc danh mục Văn học kinh điển. Tác giả: Nhiều tác giả. Dịch giả: Ngọc Anh. Phù hợp: nan. Kích thước: 14,5 x 19,2 ; Số trang: 204 trang ; NXB: NXB Văn Học ; Năm XB: 2024. Mô tả đang được cập nhật chi tiết.', 'https://dinhtibooks.com.vn/images/products/2024/07/03/large/bia-2d---nhung-cuoc-phieu-luu-ky-thu-1_1719979768.webp', 134400.00, '', '', 'Nhiều tác giả', 'Ngọc Anh', '', 'NXB Văn Học', '2024', 204, '14,5 x 19,2', 14.50, 19.20, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000237, 'Illustrated Classics - Những cuộc phiêu lưu kỳ thú - Tám mươi ngày vòng quanh thế giới, Robinson Crusoe, Con ma nhà Canterville', 'illustrated-classics-nhung-cuoc-phieu-luu-ky-thu-tam-muoi-ngay-vong-quanh-the-gioi-robinson-crusoe-con-ma-nha-canterville', '“Illustrated Classics - Những cuộc phiêu lưu kỳ thú - Tám mươi ngày vòng quanh thế giới, Robinson Crusoe, Con ma nhà Canterville” là ấn phẩm thuộc danh mục Văn học kinh điển. Tác giả: Nhiều tác giả. Dịch giả: Ngọc Anh. Phù hợp: nan. Kích thước: 14,5 x 19,2 ; Số trang: 204 trang ; NXB: NXB Văn Học ; Năm XB: 2024. Mô tả đang được cập nhật chi tiết.', 'https://dinhtibooks.com.vn/images/products/2024/07/03/large/bia-2d-nhung-cuoc-phieu-luu-ky-thu-2_1719979834.webp', 134400.00, '', '', 'Nhiều tác giả', 'Ngọc Anh', '', 'NXB Văn Học', '2024', 204, '14,5 x 19,2', 14.50, 19.20, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000238, 'Illustrated Classics - Những câu chuyện hay nhất về các nàng tiên cá', 'illustrated-classics-nhung-cau-chuyen-hay-nhat-ve-cac-nang-tien-ca', 'D ù đã qua bao nhi ê u th ế k ỷ , nh ư ng nh ữ ng c â u chuy ệ n c ổ t í ch v ề c á c ti ê n c á d ướ i bi ể n s â u v ẫ n lu ô n đượ c c á c độ c gi ả v ô c ù ng y ê u th í ch. Cu ố n s á ch Illustrated Classics - Những câu chuyện hay nhất về các nàng tiên cá l à tuy ể n t ậ p nh ữ ng c â u chuy ệ n nh ẹ nh à ng, k ỳ di ệ u v ề c á c n à ng ti ê n c á nh ư ng ẩ n ch ứ a bi ế t bao th ô ng đ i ệ p v ô c ù ng s â u s ắ c v à đầ y ý ngh ĩ a. Nh ữ ng trang s á ch s ẽ đư a b ạ n t ớ i v ù ng bi ể n Scotland để kh á m ph á nh ữ ng b í ẩ n v ề ng ườ i h ả i c ẩ u, th ă m th ú x ứ Cornwall n ướ c Anh v à l ắ ng nghe c â u chuy ệ n v ề n à ng ti ê n c á Zennor, chu du đế n đả o Guam để t ì m hi ể u v ề l ờ i nguy ề n c ủ a Sirena, hay g ặ p g ỡ ti ê n c á đế n t ừ Trung Qu ố c v ớ i n ướ c m ắ t c ó th ể bi ế n th à nh ng ọ c trai v à n ữ th ầ n n ử a ng ườ i n ử a r ắ n Dlo cai qu ả n s ô ng n ướ c ở Trinidad v à Tobago. Ch í n c â u chuy ệ n v ớ i l ờ i k ể h ấ p d ẫ n, minh h ọ a đẹ p m ắ t h ứ a h ẹ n s ẽ đ em đế n cho b ạ n đọ c nh ữ ng ph ú t gi â y tr ả i nghi ệ m th ú v ị v à đá ng nh ớ .', 'https://dinhtibooks.com.vn/images/products/2024/05/15/large/bia-2d_nhung-cau-chuyen-hay-nhat-ve-cac-nang-tien-ca_1715757558.webp', 134400.00, '', '', 'Nhiều tác giả', '', '', 'NXB Văn Học', '2024', 144, '14,5 x 19,2', 14.50, 19.20, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000239, 'Illustrated Classics - Sử thi Odyssey', 'illustrated-classics-su-thi-odyssey', 'Câu chuyện này diễn ra từ hàng nghìn năm trước ở Hy Lạp cổ đại, trong thế giới có các vị nam thần và nữ thần tâm tính khó lường với quyền năng vô biên, cai quản biển cả và bầu trời, quyết định số phận của người trần thế. Truyện kể về người anh hùng Odysseus thức trí đa mưu. Sau cuộc chiến tranh Troy kéo dài suốt mười năm ròng rã, vị anh hùng của chúng ta tìm đường về quê hương Ithaca, hòn đảo nhỏ ở Hy Lạp. Trong nhiều năm đằng đẵng, chàng dong thuyền lênh đênh trên biển cả, lạc lối giữa muôn trùng khơi, phó thác số mệnh cho các vị thần và quái vật đại dương, mãi sau này có một nữ thần động lòng thương cảm ra tay giúp đỡ chàng…', 'https://dinhtibooks.com.vn/images/products/2024/12/large/2d_su-thi-oddysey_1733391431.webp', 134400.00, '', '', 'Nhiều tác giả', 'Đăng Ngọc', '', 'NXB Hà Nội', '2024', 264, '14,5 x 19,2', 14.50, 19.20, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000240, 'Illustrated Classics - Truyện cổ tích về những người hùng bình dị', 'illustrated-classics-truyen-co-tich-ve-nhung-nguoi-hung-binh-di', 'Thế nào là một người hùng bình dị? Đó là một người nhỏ bé, hoặc dường như không có vị thế, hoặc không được ai chú ý đến, nhưng cuối cùng lại trở thành một người tự tin và dũng cảm…', 'https://dinhtibooks.com.vn/images/products/2025/05/large/bia-2d_truyen-co-tich-ve-nhung-nguoi-hung-binh-di_1747275313.webp', 134400.00, '', '', 'Nhiều tác giả', 'Ngọc Anh', '', 'NXB Thế Giới', '2025', 216, '14,5 x 19,2', 14.50, 19.20, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 11:02:23', 0),
(2000241, 'Illustrated Classics - Truyện kể hay nhất trong thần thoại Hy Lạp', 'illustrated-classics-truyen-ke-hay-nhat-trong-than-thoai-hy-lap', 'Đứng trên ban công cung điện, Helen đưa mắt ngắm nghía quang cảnh xung quanh. Người nào đi qua cũng ngước nhìn nàng với vẻ ngưỡng mộ. Ai nấy đều cho rằng Helen là người phụ nữ đẹp nhất thế gian. Tuy sống trong nhưng lụa xa hoa nhưng nàng chẳng hề hạnh phúc.', 'https://dinhtibooks.com.vn/images/products/2024/12/large/2d_truyen-ke-hay-nhat-trong-than-thoai-hy-lap_1733390954.webp', 159200.00, '', '', 'Nhiều tác giả', 'Minh Trang', '', 'NXB Hà Nội', '2024', 360, '14,5 x 19,2', 14.50, 19.20, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000242, 'Illustrated Classics - Truyện kể về các động vật dũng cảm và thông minh', 'illustrated-classics-truyen-ke-ve-cac-dong-vat-dung-cam-va-thong-minh', 'Từ khi biết kể chuyện, con người đã kể những câu chuyện về động vật. Ban đầu, những câu chuyện về động vật được kể lúc mọi người ngồi xung quanh đống lửa trại, khi những ngọn lửa hắt những cái bóng chập chờn vào màn đêm. Sau đó, những câu chuyện được viết ra thành truyện dân gian và truyện cổ tích trên khắp thế giới. Ngày nay, một số câu chuyện thiếu nhi được yêu thích nhất trên thế giới cũng là những câu chuyện kể về động vật, chẳng hạn như Gió qua rặng liễu, Ngựa ô yêu dấu, Câu chuyện rừng xanh...', 'https://dinhtibooks.com.vn/images/products/2025/05/large/bia-2d_truyen-ke-ve-cac-dong-vat-dung-cam-va-thong-minh_1747275416.webp', 134400.00, '', '', 'Nhiều tác giả', 'Ngọc Anh', '', 'NXB Thế Giới', '2025', 216, '14,5 x 19,2', 14.50, 19.20, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000243, 'Illustrated Classics - Truyện kể về những cô gái thông minh và gan dạ trong thần thoại Hy Lạp', 'illustrated-classics-truyen-ke-ve-nhung-co-gai-thong-minh-va-gan-da-trong-than-thoai-hy-lap', 'Illustrated classics - Truyện kể về những cô gái thông minh và gan dạ trong thần thoại Hy Lạp tuy ể n ch ọ n nh ữ ng c â u chuy ệ n h ấ p d ẫ n v à đặ c s ắ c nh ấ t v ề c á c n ữ th ầ n v à c á c c ô g á i trong truy ệ n th ầ n tho ạ i d ướ i g ó c nh ì n m ớ i m ẻ ph ù h ợ p th ờ i đạ i m ớ i. Cu ố n s á ch n à y đư a c á c nh â n v ậ t n ữ s ố ng l ạ i m ộ t c á ch tr ọ n v ẹ n v à tr ở th à nh trung t â m trong c â u chuy ệ n v ề h ọ . Đó l à n ữ th ầ n Đấ t M ẹ Gaia kh ở i ngu ồ n c ủ a v ạ n v ậ t, n à ng Persephone d ũ ng c ả m d ấ n th â n v à o v ươ ng qu ố c â m ph ủ , n à ng Psyche gan d ạ v ượ t qua th ử th á ch tr ê n h à nh tr ì nh t ì m ki ế m t ì nh y ê u, ti ê n n ữ Daphne tr ở th à nh bi ể u t ượ ng c à nh nguy ệ t qu ế vinh quang, n ữ th ầ n ma thu ậ t Circe v ớ i nh ữ ng chuy ệ n huy ề n b í , n à ng Penelope t à i tr í , n ữ th ầ n Artemis gi ỏ i giang m ư u tr í , n à ng Atalanta c ó t à i ch ạ y nhanh xu ấ t ch ú ng v à n ữ th ầ n Athena th ô ng minh uy ê n b á c. V ớ i c ố t truy ệ n m ớ i l ạ , gi ọ ng v ă n hi ệ n đạ i, l ô i cu ố n c ù ng tranh minh h ọ a s ố ng độ ng, cu ố n s á ch s ẽ d ẫ n d ắ t độ c gi ả v à o nh ữ ng cu ộ c phi ê u l ư u ly k ỳ c ủ a c á c c ô g á i th ú v ị nh ấ t trong th ầ n tho ạ i Hy L ạ p.', 'https://dinhtibooks.com.vn/images/products/2024/05/15/large/2d_truyen-ke-ve-nhung-co-gai-thong-minh-va-gan-da-trong-than-thoai-hy-lap_1715757243.webp', 134400.00, '', '', 'Nhiều tác giả', 'Minh Trang', '', 'NXB Thanh Niên', '2024', 188, '14,5 x 19,2', 14.50, 19.20, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000244, 'Illustrated Special Edition - Heidi', 'illustrated-special-edition-heidi', '“Illustrated Special Edition - Heidi” là ấn phẩm thuộc danh mục Văn học kinh điển. Tác giả: Johanna Spyri. Dịch giả: Linh Chi. Phù hợp: nan. Kích thước: 24 x 26,5 ; Số trang: 92 trang ; NXB: NXB Văn Học ; Năm XB: 2024. Mô tả đang được cập nhật chi tiết.', 'https://dinhtibooks.com.vn/images/products/2024/07/04/large/bia-2d_heidi_1720077415.webp', 159200.00, '', '', 'Johanna Spyri', 'Linh Chi', '', 'NXB Văn Học', '2024', 92, '24 x 26,5', 24.00, 26.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000245, 'Illustrated Special Edition - Khu vườn bí mật', 'illustrated-special-edition-khu-vuon-bi-mat', '“Illustrated Special Edition - Khu vườn bí mật” là ấn phẩm thuộc danh mục Văn học kinh điển. Tác giả: Frances Hodgson Burnett. Dịch giả: Linh Chi. Phù hợp: nan. Kích thước: 24 x 26,5 ; Số trang: 92 trang ; NXB: NXB Thanh Niên ; Năm XB: 2024. Mô tả đang được cập nhật chi tiết.', 'https://dinhtibooks.com.vn/images/products/2024/07/04/large/bia-2d_khu-vuon-bi-mat_1720077255.webp', 159200.00, '', '', 'Frances Hodgson Burnett', 'Linh Chi', '', 'NXB Thanh Niên', '2024', 92, '24 x 26,5', 24.00, 26.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000246, 'Illustrated Special Edition - Peter Pan', 'illustrated-special-edition-peter-pan', '“Illustrated Special Edition - Peter Pan” là ấn phẩm thuộc danh mục Văn học kinh điển. Tác giả: J. M. Barrie. Dịch giả: Linh Chi. Phù hợp: nan. Kích thước: 24 x 26,5 ; Số trang: 92 trang ; NXB: NXB Thanh Niên ; Năm XB: 2024. Mô tả đang được cập nhật chi tiết.', 'https://dinhtibooks.com.vn/images/products/2024/07/04/large/bia-2d_peter-pan_1720077605.webp', 142400.00, '', '', 'J. M. Barrie', 'Linh Chi', '', 'NXB Thanh Niên', '2024', 92, '24 x 26,5', 24.00, 26.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000247, 'Khu vườn bí mật', 'khu-vuon-bi-mat', 'Khi Mary Lennox được gửi đến trang viên Misselthwaite để sống với chú của cô bé, mọi người đều bảo rằng cô là đứa trẻ khó ưa nhất mà họ từng thấy. Nói vậy kể ra cũng có lý. Cô có khuôn mặt thon nhỏ, thân hình mảnh khảnh, mái tóc mỏng sáng màu và vẻ mặt cau có. Tóc cô màu vàng và khuôn mặt cũng vàng vọt vì cô sinh ra ở Ấn Độ, cứ nay ốm mai đau', 'https://dinhtibooks.com.vn/images/products/2025/07/large/2d_bia_khu-vuon-bi-mat_1751612456.webp', 118400.00, '', '', 'Frances Hodgson Burnett', 'Đăng Ngọc', '', 'NXB Phụ Nữ', '2025', 400, '14,5 x 20,5', 14.50, 20.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000248, 'Lâu đài thần bí', 'lau-dai-than-bi', '“Lâu đài thần bí” là ấn phẩm thuộc danh mục Văn học kinh điển. Tác giả: Edith Nesbit. Dịch giả: Đăng Ngọc. Phù hợp: nan. Kích thước: 14,5 x 20,5 ; Số trang: 368 trang ; NXB: NXB Văn Học ; Năm XB: 2024. Mô tả đang được cập nhật chi tiết.', 'https://dinhtibooks.com.vn/images/products/2024/11/large/bia-2d_lau-dai-than-bi_1731119536.webp', 95200.00, '', '', 'Edith Nesbit', 'Đăng Ngọc', '', 'NXB Văn Học', '2024', 368, '14,5 x 20,5', 14.50, 20.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000249, 'Những kỳ vọng lớn lao 1', 'nhung-ky-vong-lon-lao-1', 'N hững kỳ vọng lớn lao l à m ộ t trong nh ữ ng t á c ph ẩ m n ổ i ti ế ng nh ấ t c ủ a nh à v ă n xu ấ t ch ú ng ng ườ i Anh Charles Dickens. Đượ c coi l à m ộ t trong nh ữ ng t á c ph ẩ m xu ấ t s ắ c nh ấ t c ủ a v ă n h ọ c th ế gi ớ i, cu ố n ti ể u thuy ế t k ể l ạ i sinh độ ng cu ộ c đờ i c ủ a Pip t ừ th ờ i th ơ ấ u đế n khi tr ưở ng th à nh, m ô t ả c á ch c ậ u l ớ n l ê n v à c á c y ế u t ố nh ư h ệ th ố ng t ầ ng l ớ p x ã h ộ i, quan đ i ể m v à ho à i b ã o g ó p ph ầ n v à o s ự thay đổ i trong t ư duy v à cu ộ c s ố ng c ủ a nh â n v ậ t. Pip đã c ó nh ữ ng cu ộ c g ặ p g ỡ đị nh m ệ nh mang t í nh b ướ c ngo ặ t, đư a c ậ u t ừ đứ a tr ẻ m ồ c ô i s ố ng ở gi ữ a ch ố n đầ m l ầ y v ù ng th ô n qu ê chuy ể n l ê n th à nh ph ố London để tr ở th à nh m ộ t qu ý ô ng. Đượ c xu ấ t b ả n n ă m 1861, Những kỳ vọng lớn lao đề c ậ p m ộ t c á ch tinh t ế v à x ú c độ ng c á c v ấ n đề mang t í nh th ờ i đạ i: Đó h à nh tr ì nh ho à n thi ệ n b ả n th â n, t ì m ki ế m ý ngh ĩ a cu ộ c s ố ng, c á ch ứ ng x ử trong t ì nh y ê u, tr á ch nhi ệ m v ề qu ả n l ý th ờ i gian v à t à i ch í nh, k ế t giao v ớ i b ạ n t ố t, l ố i s ố ng bi ế t ơ n v à vi ệ c tr â n tr ọ ng m ố i quan h ệ trong gia đì nh. Qua c á ch quan s á t s â u s ắ c c á c v ấ n đề x ã h ộ i c ủ a Dickens, k ế t h ợ p v ớ i ngh ệ thu ậ t k ể chuy ệ n kh ô ng ai s á nh k ị p v à t à i x â y d ự ng nh â n v ậ t đặ c s ắ c, t á c ph ẩ m l à m say đắ m độ c gi ả ở m ọ i l ứ a tu ổ i, thu ộ c nhi ề u th ế h ệ v à chinh ph ụ c c ả gi ớ i ph ê b ì nh, tr ở th à nh m ộ t ki ệ t t á c x ứ ng đá ng hi ệ n di ệ n tr ê n m ọ i k ệ', 'https://dinhtibooks.com.vn/images/products/2024/06/21/large/2d_nhung-ky-vong-lon-lao-1_1718935199.webp', 135200.00, '', '', 'Charles Dickens', 'Quỳnh Phương', '', 'NXB Thanh Niên', '2024', 416, '14,5 x 20,5', 14.50, 20.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000250, 'Những kỳ vọng lớn lao 2', 'nhung-ky-vong-lon-lao-2', 'N hững kỳ vọng lớn lao l à m ộ t trong nh ữ ng t á c ph ẩ m n ổ i ti ế ng nh ấ t c ủ a nh à v ă n xu ấ t ch ú ng ng ườ i Anh Charles Dickens. Đượ c coi l à m ộ t trong nh ữ ng t á c ph ẩ m xu ấ t s ắ c nh ấ t c ủ a v ă n h ọ c th ế gi ớ i, cu ố n ti ể u thuy ế t k ể l ạ i sinh độ ng cu ộ c đờ i c ủ a Pip t ừ th ờ i th ơ ấ u đế n khi tr ưở ng th à nh, m ô t ả c á ch c ậ u l ớ n l ê n v à c á c y ế u t ố nh ư h ệ th ố ng t ầ ng l ớ p x ã h ộ i, quan đ i ể m v à ho à i b ã o g ó p ph ầ n v à o s ự thay đổ i trong t ư duy v à cu ộ c s ố ng c ủ a nh â n v ậ t. Pip đã c ó nh ữ ng cu ộ c g ặ p g ỡ đị nh m ệ nh mang t í nh b ướ c ngo ặ t, đư a c ậ u t ừ đứ a tr ẻ m ồ c ô i s ố ng ở gi ữ a ch ố n đầ m l ầ y v ù ng th ô n qu ê chuy ể n l ê n th à nh ph ố London để tr ở th à nh m ộ t qu ý ô ng. Đượ c xu ấ t b ả n n ă m 1861, Những kỳ vọng lớn lao đề c ậ p m ộ t c á ch tinh t ế v à x ú c độ ng c á c v ấ n đề mang t í nh th ờ i đạ i: Đó h à nh tr ì nh ho à n thi ệ n b ả n th â n, t ì m ki ế m ý ngh ĩ a cu ộ c s ố ng, c á ch ứ ng x ử trong t ì nh y ê u, tr á ch nhi ệ m v ề qu ả n l ý th ờ i gian v à t à i ch í nh, k ế t giao v ớ i b ạ n t ố t, l ố i s ố ng bi ế t ơ n v à vi ệ c tr â n tr ọ ng m ố i quan h ệ trong gia đì nh. Qua c á ch quan s á t s â u s ắ c c á c v ấ n đề x ã h ộ i c ủ a Dickens, k ế t h ợ p v ớ i ngh ệ thu ậ t k ể chuy ệ n kh ô ng ai s á nh k ị p v à t à i x â y d ự ng nh â n v ậ t đặ c s ắ c, t á c ph ẩ m l à m say đắ m độ c gi ả ở m ọ i l ứ a tu ổ i, thu ộ c nhi ề u th ế h ệ v à chinh ph ụ c c ả gi ớ i ph ê b ì nh, tr ở th à nh m ộ t ki ệ t t á c x ứ ng đá ng hi ệ n di ệ n tr ê n m ọ i k ệ s á ch.', 'https://dinhtibooks.com.vn/images/products/2024/06/21/large/2d_nhung-ky-vong-lon-lao-2_1718935541.webp', 135200.00, '', '', 'Charles Dickens', 'Quỳnh Phương', '', 'NXB Thanh Niên', '2024', 420, '14,5 x 20,5', 14.50, 20.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000251, 'Nàng công chúa nhỏ', 'nang-cong-chua-nho', 'Một ngày đông ảm đạm nọ, màn sương dày vàng ệch nặng nề bao trùm khắp các nẻo đường London. Phố xá phải lên đèn giữa ban ngày và những ô kính ở các cửa hàng cũng được thắp đèn ga sáng rực như thể đã tối trời, có một cô bé nom thật lạ lùng ngồi cùng cha trong một cỗ xe ngựa đương chậm rãi lăn bánh qua những con phố lớn', 'https://dinhtibooks.com.vn/images/products/2025/07/large/2d_nang-cong-chua-nho_1751612559.webp', 110400.00, '', '', 'Frances Hodgson Burnett', 'Phan Ái Hân', '', 'NXB Lao Động', '2025', 332, '14.5 x 20.5', 14.50, 20.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000252, 'Peter Pan', 'peter-pan', 'Câu chuyện bắt đầu trong phòng trẻ của gia đình Darling ở London, nơi Wendy, John và Michael đang đi ngủ thì bất ngờ trước sự xuất hiện của Peter Pan và nàng tiên Tinker Bell. Ba chị em đã theo Peter đến Neverland và chuyến phiêu lưu của họ bắt đầu. Đề cập đến các chủ đề như tình mẫu tử, thiện, ác và tình yêu, Peter Pan là một cuộc phiêu lưu trong văn chương mang đến cho người đọc cái nhìn hoài niệm về quá khứ trẻ thơ đầy mơ mộng, khuyến khích ta nhìn lại bản thân từng trẻ trung và giàu trí tưởng tượng biết bao, nhắc nhở ta đừng bao giờ ngừng tin tưởng chính mình. Câu chuyện thiếu nhi kinh điển của J. M. Barrie không chỉ là câu chuyện về tiên, về những tên cướp biển hay gã thuyền trưởng khét tiếng Hook, Peter Pan còn là cuộc đấu tranh vượt thời gian của những tâm hồn giữa việc giữ mãi sự ngây thơ hồn nhiên hay cần lớn lên và trưởng thành.', 'https://dinhtibooks.com.vn/images/products/2024/05/28/large/bia-2d_perter-pan_1716862354.webp', 87200.00, '', '', 'J. M. Barrie', 'Khánh An', '', 'NXB Thanh Niên', '2024', 288, '14.5 x 20.5', 14.50, 20.50, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000253, 'Sơn Hải Kinh', 'son-hai-kinh', 'T rong kho tàng điển tịch của người Trung Hoa, Sơn hải kinh là một bộ sách rất đặc biệt. Nó bao hàm nội dung về rất nhiều phương diện, từ địa lý, thiên văn, lịch sử, thần thoại, khí tượng cho tới động vật, thực vật, khoáng vật, y dược, tôn giáo. Những ghi chép trong sách tuy cũng có một số có thể ấn chứng với thực tế, nhưng phần nhiều vẫn mang màu sắc thần thoại, có lẽ được dựa vào trí tưởng tượng mà viết nên. Cũng bởi thế mà người thời Thanh khi biên soạn Tứ khố toàn thư có nhận định rằng sách này “ba hoa về những chuyện thần tiên ma quái, không có gì là chân thực, thực là tổ của dòng tiểu thuyết vậy. Đưa vào Sử bộ , không thể chấp thuận được vậy”, rồi bèn đổi sang Tử bộ , xếp vào loại Tiểu thuyết gia .', 'https://dinhtibooks.com.vn/images/products/2024/09/large/son-hai-kinh_2d_1726470386.webp', 127200.00, '', '', 'Khuyết Danh', 'Nguyễn Đức Vịnh', '', 'NXB Văn Học', '2024', 304, '16 x 24', 16.00, 24.00, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0),
(2000254, 'Sơn Hải Kinh Đồ', 'son-hai-kinh-do', 'S ơn hải kinh là một cuốn sách lạ, tương truyền đã thành sách từ thời thượng cổ ở xứ Trung Hoa. Dĩ nhiên thời thượng cổ là một khái niệm mơ hồ, nhưng do nhiều nguyên nhân, ngày nay người ta chẳng thể khảo cứu nổi nó được làm ra cụ thể vào thời điểm nào, tác giả là ai cũng không rõ, chỉ biết nó ít nhất cũng đã được lưu truyền phổ biến từ thời sử gia Tư Mã Thiên còn sống, tức là cách nay hơn hai nghìn năm. Nội dung sách chủ yếu miêu tả về một thế giới cổ xưa với các ngọn núi, các vùng biển, các vùng đất và các bộ tộc cũng như các loài sinh vật sống ở trên đó, xét chung ra có thể nói là bao trùm từ thiên văn tới địa lý, từ lịch sử tới thần thoại, từ khí tượng tới tôn giáo, mặt nào cũng có đả động, nhưng ít nhiều đều mang hơi hướng phi thực tế cùng nhiều màu sắc thần thoại.', 'https://dinhtibooks.com.vn/images/products/2024/09/large/son-hai-kinh-do_2d_1726470709.webp', 127200.00, '', '', 'Khuyết Danh', 'Nguyễn Đức Vịnh', '', 'NXB Văn Học', '2024', 176, '16 x 24', 16.00, 24.00, 0.00, 0, 0, NULL, NULL, NULL, 0, 1, '2025-09-25 10:05:41', '2025-09-25 18:14:02', 0);
